const gg = $json || {};
const isRevision = (req.decision==='changes') || (req.task_type==='approval');
let lookedTitle='', lookedPkg='', lookedType='';
try{ const sd=$getWorkflowStaticData('global'); const pend=Array.isArray(sd.pending)?sd.pending:[]; const rec=pend.find(p=>p['الرمز']===req.topic_code); if(rec){lookedTitle=rec['عنوان الموضوع']||''; lookedPkg=rec['الباقة']||''; lookedType=rec['النوع']||'';} }catch(e){}
const src = (req.source_text && req.source_text.trim()) ? req.source_text : (gg.full_text || '');
const code = isRevision ? ('N'+Date.now().toString().slice(-6)) : ((req.topic_code && req.topic_code.trim()) ? req.topic_code : ('N'+Date.now().toString().slice(-6)));
const title = gg.title || req.new_title || lookedTitle || req.topic_code || code;
const pkg = req.package || lookedPkg || 'جديد';
