const revision_note = req.revision_note || req.comment || '';
return [{json:{...req, topic_code:code, title, package:pkg, output_type, num_slides:gg.num_slides||0, full_text:src, refs:gg.refs||[], grounding_ok:!!(src&&src.trim()), revision_note}}];

const item = $input.first().json;
const strings = [];
(function walk(v){ if(typeof v==='string') strings.push(v); else if(Array.isArray(v)) v.forEach(walk); else if(v&&typeof v==='object') Object.values(v).forEach(walk); })(item);
function tryParse(s){ let t=String(s||'').replace(/```json/gi,'```').split('```').join('').trim(); const a=t.indexOf('{'),b=t.lastIndexOf('}'); if(a<0||b<=a) return null; t=t.slice(a,b+1); try{return JSON.parse(t);}catch(e){return null;} }
let parsed=null;
const cand=strings.filter(s=>/slides|cover/i.test(s)).sort((x,y)=>y.length-x.length);
for(const s of cand){ parsed=tryParse(s); if(parsed) break; }
if(!parsed){ for(const s of strings.sort((x,y)=>y.length-x.length)){ parsed=tryParse(s); if(parsed) break; } }
if(!parsed) throw new Error('Could not extract JSON.');
let meta={}; try{ meta=$('دمج التأصيل').first().json; }catch(e){}
if(!parsed.code && meta && meta.topic_code) parsed.code=meta.topic_code;
const arr=v=>Array.isArray(v)?v:[];
const txt=v=>arr(v).map(x=> (x&&typeof x==='object') ? (x.text||x.title||x.desc||x.step||x.point||x.q||'') : x).filter(x=>x!=null&&x!=='');
const objCards=v=>arr(v).map(x=> (x&&typeof x==='object') ? {icon:x.icon||'FaInfoCircle',title:x.title||x.name||'',desc:x.desc||x.description||x.text||''} : {icon:'FaInfoCircle',title:String(x),desc:''});
const objItems=v=>arr(v).map(x=> (x&&typeof x==='object') ? {icon:x.icon||'FaCheck',title:x.title||x.name||x.text||''} : {icon:'FaCheck',title:String(x)});
if(!parsed.cover||typeof parsed.cover!=='object') parsed.cover={icon:'FaShieldAlt',title:(meta&&meta.title)||parsed.code||'عرض توعوي',subtitle:'',quote:''};
parsed.slides=arr(parsed.slides).map(s=>{ if(!s||typeof s!=='object') return null; const t=s.type||'cards';
  if(t==='cards'||t==='cardsDesc'){ const src=(s.cards&&s.cards.length)?s.cards:(s.items||s.points); s.cards=objCards(src); }
  else if(t==='compact'||t==='emergency'){ const src=(s.items&&s.items.length)?s.items:(s.cards||s.points); s.items=objItems(src); if(t==='emergency'){ s.exampleText=s.exampleText||''; } }
  else if(t==='numbered'){ s.steps=txt((s.steps&&s.steps.length)?s.steps:(s.points||s.items)); }
  else if(t==='stairs'){ s.points=txt((s.points&&s.points.length)?s.points:(s.steps||s.items)); }
  else if(t==='dodont'){ s.do=txt(s.do); s.dont=txt(s.dont); }
  else if(t==='scenarios'){ s.scenarios=arr(s.scenarios).map(x=>({num:x.num||'',q:x.q||x.question||'',a:x.a||x.answer||''})); }
  else if(t==='quiz'){ s.qa=arr(s.qa).map(x=>({q:x.q||x.question||'',a:x.a||x.answer||''})); }
  else if(t==='closing'){ s.points=txt(s.points); }
  return s;
}).filter(Boolean);
return [{ json: parsed }];

