let __H=null; try{ if(this&&this.helpers&&this.helpers.httpRequest) __H=this.helpers; }catch(e){} const __APPROVED='adcda.gov.ae,moi.gov.ae,dcd.gov.ae,shjcd.gov.ae,adpolice.gov.ae,ncema.gov.ae,ncm.gov.ae,doh.gov.ae,adphc.gov.ae,mohap.gov.ae,mohre.gov.ae,adafsa.gov.ae,adek.gov.ae,dmt.gov.ae,awqaf.gov.ae,rcuae.ae,tamm.abudhabi,u.ae,haj.gov.sa,moh.gov.sa,998.gov.sa,nfpa.org,usfa.fema.gov,cpsc.gov,osha.gov,nhtsa.gov,schoolsafety.gov,cdc.gov,cpr.heart.org,redcross.org,ready.gov,who.int,ifrc.org,cfpa-e.eu,undrr.org,ilo.org,unicef.org'.split(','); let lc={checked:0,live:0,dead:0,offdomain:0,results:[],note:''}; try{ const __urls=(Array.isArray(data.sources)?data.sources:[]).map(function(u){var mm=String(u).match(/https?:\/\/[^\s,|\"'<>]+/);return mm?mm[0]:'';}).filter(Boolean).slice(0,6); for(const u of __urls){ let host=''; try{ const hm=u.match(/^https?:\/\/([^\/?#]+)/i); if(hm) host=hm[1].replace(/^www\./,'').toLowerCase(); }catch(e){} const approved=__APPROVED.some(function(dn){return host===dn||host.endsWith('.'+dn);}); let ok=null,code2=null; if(__H){ try{ const res=await __H.httpRequest({method:'GET',url:u,timeout:8000,returnFullResponse:true,ignoreHttpStatusErrors:true,headers:{'User-Agent':'Mozilla/5.0'}}); code2=res.statusCode||0; ok=(code2>=200&&code2<400); }catch(e){ code2=-1; ok=false; } } lc.results.push({url:u,host:host,approved:approved,ok:ok,code:code2}); } lc.checked=lc.results.length; lc.live=lc.results.filter(function(r){return r.ok===true;}).length; lc.dead=lc.results.filter(function(r){return r.ok===false;}).length; lc.offdomain=lc.results.filter(function(r){return !r.approved;}).length; }catch(e){ lc.note='تعذّر فحص الروابط'; } const sd = $getWorkflowStaticData('global'); sd.pending=Array.isArray(sd.pending)?sd.pending:[];
const rec = {'فحص الروابط':JSON.stringify(lc),'الرمز':code,'الباقة':m.package||'جديد','عنوان الموضوع':topicTitle,'الحالة المرجعية':'','حالة الإنتاج':'بانتظار الاعتماد','تاريخ الإنتاج':new Date().toISOString().slice(0,10),'رابط الملف (OneDrive)':'','الإصدار':'','ملاحظات':'نوع: بوست (صورة)','المصادر':sources,'النوع':'post','نص البوست':readable,'بيانات البوست':JSON.stringify(data),'اللغة':lang2};
