function strs(o){const a=[];(function w(v){if(typeof v==='string')a.push(v);else if(Array.isArray(v))v.forEach(w);else if(v&&typeof v==='object')Object.values(v).forEach(w);})(o);return a;}
function tp(s){let t=String(s||'').replace(/```json/gi,'```').split('```').join('').trim();const a=t.indexOf('{'),b=t.lastIndexOf('}');if(a<0||b<=a)return null;try{return JSON.parse(t.slice(a,b+1));}catch(e){return null;}}
const S=strs($input.first().json).sort((a,b)=>b.length-a.length);
let d=null;for(const s of S){if(/suggestions/.test(s)){d=tp(s);if(d&&d.suggestions)break;}}
if(!d){for(const s of S){d=tp(s);if(d)break;}}
d=d||{suggestions:[]};
if(!Array.isArray(d.suggestions))d.suggestions=[];
return [{json:{suggestions:d.suggestions, count:d.suggestions.length}}];

const content=$input.first().json;
let brief='';try{brief=$('تجهيز الموجز').first().json.brief||'';}catch(e){}
try{if(!brief)brief=$('دمج التأصيل').first().json.full_text||'';}catch(e){}
function strs(o){const a=[];(function w(v){if(typeof v==='string')a.push(v);else if(Array.isArray(v))v.forEach(w);else if(v&&typeof v==='object')Object.values(v).forEach(w);})(o);return a;}
const codeNum=String(content.code||'').replace(/[^0-9]/g,'');
let txt=strs(content).join(' ');
if(codeNum){txt=txt.split(codeNum).join(' ');}
const nums=(txt.match(/[0-9]{2,}/g)||[]).filter(function(n){return n!=='999' && n!==codeNum && !/^(19|20)[0-9]{2}$/.test(n);});
const unv=[...new Set(nums)].filter(function(n){return brief.indexOf(n)<0;});
let score=100;score-=unv.length*15;const ns=(content.slides||[]).length;if(ns<5)score-=15;if(!brief||brief.length<200)score-=20;score=Math.max(0,Math.min(100,score));
