const APPROVED='adcda.gov.ae,moi.gov.ae,dcd.gov.ae,shjcd.gov.ae,adpolice.gov.ae,ncema.gov.ae,ncm.gov.ae,doh.gov.ae,adphc.gov.ae,mohap.gov.ae,mohre.gov.ae,adafsa.gov.ae,adek.gov.ae,dmt.gov.ae,awqaf.gov.ae,rcuae.ae,tamm.abudhabi,u.ae,haj.gov.sa,moh.gov.sa,998.gov.sa,nfpa.org,usfa.fema.gov,cpsc.gov,osha.gov,nhtsa.gov,schoolsafety.gov,cdc.gov,cpr.heart.org,redcross.org,ready.gov,who.int,ifrc.org,cfpa-e.eu,undrr.org,ilo.org,unicef.org'.split(',');
