  const dt=dstr?new Date(dstr):null;
  if(dt && !isNaN(dt.getTime())){ const months=(now-dt)/(1000*60*60*24*30); if(months>=FRESH_MONTHS) reasons.push('مرّ '+Math.floor(months)+' شهرًا منذ الإنتاج — يُنصح بالمراجعة'); }
  const src=(it['المصادر']||'')+'';
  const urls=(src.match(/https?:\/\/[^\s,|\"'<>]+/g)||[]).slice(0,4);
  if(H){ for(const u of urls){ try{ const res=await H.httpRequest({method:'GET',url:u,timeout:8000,returnFullResponse:true,ignoreHttpStatusErrors:true,headers:{'User-Agent':'Mozilla/5.0'}}); if(!(res.statusCode>=200&&res.statusCode<400)) reasons.push('رابط مصدر لا يفتح'); }catch(e){ reasons.push('رابط مصدر لا يفتح'); } } }
  if(reasons.length){ flagged.push({code:it['الرمز']||'', title:it['عنوان الموضوع']||'', reasons:[...new Set(reasons)]}); }
}
sd.monitor={ checkedAt: now.toISOString().slice(0,10), flaggedCount: flagged.length, scanned: scanned, flagged: flagged };
return [{json:{__monitor:true, monitor:sd.monitor}}];

