function normDigits(t) {
  const ar = "٠١٢٣٤٥٦٧٨٩", fa = "۰۱۲۳۴۵۶۷۸۹";
  return String(t == null ? "" : t).replace(/[٠-٩۰-۹]/g, d => {
    const i = ar.indexOf(d); if (i >= 0) return String(i);
    const j = fa.indexOf(d); return j >= 0 ? String(j) : d;
  });
}
// استخراج النصوص — يشمل حقول البنية الحية: items، q/a، desc
function slideTexts(s) {
  const out = [];
  const push = v => { if (v != null && typeof v !== 'object' && String(v).trim()) out.push(String(v)); };
  const arr = v => Array.isArray(v) ? v : (v == null ? [] : [v]);
  push(s.title); push(s.name); push(s.desc); push(s.description);
  push(s.text); push(s.tagline); push(s.exampleText); push(s.quote);
  arr(s.points).forEach(push); arr(s.steps).forEach(push); arr(s.items).forEach(v => {
    if (v && typeof v === 'object') { push(v.name); push(v.title); push(v.desc); push(v.text); } else push(v);
  });
  arr(s.do).forEach(push); arr(s.dont).forEach(push);
  arr(s.cards).forEach(c => { if (c && typeof c === 'object') { push(c.name); push(c.title); push(c.desc); push(c.text); } else push(c); });
  arr(s.scenarios).forEach(c => { if (c && typeof c === 'object') { push(c.q); push(c.a); push(c.question); push(c.answer); push(c.text); } });
  arr(s.qa).forEach(c => { if (c && typeof c === 'object') { push(c.q); push(c.a); push(c.question); push(c.answer); } });
  arr(s.pairs).forEach(c => { if (c && typeof c === 'object') { push(c.instead_of); push(c.do_this); } });
  arr(s.groups).forEach(c => { if (c && typeof c === 'object') { push(c.group); push(c.behavior); } });
  arr(s.when).forEach(push); arr(s.say).forEach(push);
  arr(s.report).forEach(push); arr(s.safe_return).forEach(push); arr(s.disposal).forEach(push);
  return out;
}
function slideItems(s) {
  const arr = v => Array.isArray(v) ? v : [];
  const lists = [arr(s.points), arr(s.steps), arr(s.items), arr(s.do), arr(s.dont), arr(s.cards), arr(s.scenarios), arr(s.qa), arr(s.pairs), arr(s.groups), arr(s.when), arr(s.say), arr(s.report), arr(s.safe_return), arr(s.disposal)];
  return lists.reduce((x, y) => (y.length > x.length ? y : x), []);
}
function slideBullets(s) {
  const out = [];
