}
const wordCount = t => normDigits(t).trim().split(/\s+/).filter(Boolean).length;
const EMERGENCY_CTX = /(طوار[ئىي]|اتصل|اتصال|الهاتف|الرقم|hotline|نجدة|إسعاف|الإسعاف|الدفاع المدني)/;
const FORBIDDEN_NUM = /(?:^|[^\d])(911|112|998|997|996|995|990|901|118|122|123)(?:[^\d]|$)/;
function findFutureDates(text) {
  const t = normDigits(text); const found = [];
  const re = /(20\d{2})[\/\-.](\d{1,2})[\/\-.](\d{1,2})|(\d{1,2})[\/\-.](\d{1,2})[\/\-.](20\d{2})/g;
  let m; const now = Date.now(), yNow = new Date().getFullYear();
  while ((m = re.exec(t)) !== null) {
    let y, mo, d;
    if (m[1]) { y = +m[1]; mo = +m[2]; d = +m[3]; } else { d = +m[4]; mo = +m[5]; y = +m[6]; }
    const dt = new Date(y, mo - 1, d);
    if (!isNaN(dt) && dt.getTime() > now) found.push(m[0]);
  }
  let ym; const yr = /(?:^|[^\d])(20\d{2})(?:[^\d]|$)/g;
  while ((ym = yr.exec(t)) !== null) { if (+ym[1] > yNow) found.push(ym[1]); }
  return [...new Set(found)];
}

const deck = $input.first().json;
