  catch (e) { return { parse_error: true, raw: clean.slice(0, 400) }; }
}
const LIST_FIELDS = ['items', 'points', 'steps', 'cards', 'scenarios', 'qa', 'do', 'dont', 'pairs', 'groups', 'when', 'say', 'report', 'safe_return', 'disposal', 'sources'];
const isRefs = s => /^(refs|references|sources|closing|مصادر)$/i.test(String((s && s.type) || ''));
function slideTexts(s) {
  const out = [];
  const push = v => { if (v != null && typeof v !== 'object' && String(v).trim()) out.push(String(v)); };
  const arr = v => Array.isArray(v) ? v : (v == null ? [] : [v]);
  ['title','name','desc','description','text','tagline','exampleText','quote','subtitle','scenario','main_message','stat','stat_meaning','curiosity_hook','truth_opener','critical_dont','empowerment_line','interaction_question','scenario_callback','scenario_close','surprise_fact'].forEach(f => push(s[f]));
  LIST_FIELDS.forEach(f => arr(s[f]).forEach(v => {
    if (v && typeof v === 'object') ['name','title','desc','text','q','a','question','answer','instead_of','do_this','group','behavior'].forEach(k => push(v[k]));
    else push(v);
  }));
  return out;
}
