// 🚪 بوابة الإحصائية الحتمية v2 — طبقتان: القائمة المعتمدة ثم المصادر الرسمية الجديدة (فحص كود، لا وعود AI)
function extractText(o){if(o==null)return '';if(typeof o==='string')return o;if(Array.isArray(o))return o.map(extractText).filter(Boolean).join('\n');if(typeof o!=='object')return String(o);if(typeof o.text==='string')return o.text;for(const k of ['output','content','message','choices','text']){if(o[k]!=null){const t=extractText(o[k]);if(t)return t;}}return '';}
const raw = $('تجهيز الموجز الخام').first().json;
const WL = ['who.int','cdc.gov','nfpa.org','nhtsa.gov','osha.gov','ready.gov','undrr.org','ilo.org','unicef.org','u.ae','government.ae','adcda.gov.ae','dcd.gov.ae','moi.gov.ae','mohap.gov.ae','ncema.gov.ae','adphc.gov.ae'];
const ORG_WL = ['ifrc.org','icrc.org','iso.org','oecd.org','worldbank.org','unep.org','undp.org','unesco.org','unfpa.org','wmo.int','redcross.org'];
function hostOf(u){ return String(u).replace(/^https?:\/\//,'').split('/')[0].toLowerCase(); }
function classify(host){
  if (WL.some(d => host === d || host.endsWith('.' + d))) return 'approved';
  if (/\.gov$/.test(host) || /\.gov\.[a-z]{2}$/.test(host) || /\.int$/.test(host) || /\.un\.org$/.test(host) || host === 'un.org' || /(^|\.)europa\.eu$/.test(host)) return 'candidate';
  if (ORG_WL.some(d => host === d || host.endsWith('.' + d))) return 'candidate';
  return 'rejected';
}
let stat = null, tier = 0;
try {
  const inp = $input.first().json;
  if (inp && inp.t1_ok === true && inp.t1_stat) { stat = inp.t1_stat; tier = 1; }
  else {
    const t = extractText(inp) || '';
    const m = String(t).replace(/\u0060\u0060\u0060json/gi,'').replace(/\u0060\u0060\u0060/g,'').match(/\{[\s\S]*\}/);
    const j = m ? JSON.parse(m[0]) : null;
    if (j && j.found === true && j.stat_ar && j.source && j.source.url) {
      const host = hostOf(j.source.url);
      const cls = classify(host);
      const okYear = /^(201[5-9]|202[0-6])$/.test(String(j.source.year||''));
      const okBase = okYear && /\d/.test(String(j.stat_ar)) && String(j.stat_ar).trim().split(/\s+/).length <= 20;
      if (okBase && cls !== 'rejected') { stat = j; tier = (cls === 'approved') ? 1 : 2; }
    }
  }
} catch (e) { /* بلا إحصائية — الموجز يمر كما هو */ }
let brief = String(raw.brief || '');
if (stat) {
  brief += '\n\n=== إحصائية مؤصلة (من وكيل البحث المعتمد — استخدمها حرفيًا في شريحة 3 مع المصدر والسنة) ===\n'
    + stat.stat_ar + '\nالمصدر: ' + stat.source.name + ' (' + stat.source.year + ') ' + stat.source.url
    + '\nالتفسير: ' + (stat.stat_meaning_ar || '');
  if (tier === 2) {
    stat.new_source = true;
    try {
      const sd = $getWorkflowStaticData('global');
      sd.candidateSources = sd.candidateSources || [];
      sd.candidateSources.push({ domain: hostOf(stat.source.url), name: String(stat.source.name||''), year: stat.source.year, url: String(stat.source.url||''), topic: String(raw.title||''), at: new Date().toISOString(), status: 'بانتظار المراجعة' });
      if (sd.candidateSources.length > 200) sd.candidateSources = sd.candidateSources.slice(-200);
    } catch(e) {}
  }
}
return [{ json: Object.assign({}, raw, { brief, sourced_stat: stat }) }];

