const a = $input.first().json;
function pickText(o){
  if(!o) return '';
  if(typeof o==='string') return o;
  if(Array.isArray(o.output)){
    var parts=[];
    o.output.forEach(function(m){
      if(m && Array.isArray(m.content)){ m.content.forEach(function(c){ if(c && typeof c.text==='string') parts.push(c.text); }); }
      else if(m && typeof m.text==='string'){ parts.push(m.text); }
      else if(typeof m==='string'){ parts.push(m); }
    });
    if(parts.length) return parts.join('\n');
  }
  if(typeof o.output_text==='string') return o.output_text;
  if(typeof o.text==='string') return o.text;
  if(typeof o.output==='string') return o.output;
  if(typeof o.response==='string') return o.response;
  if(o.message && typeof o.message.content==='string') return o.message.content;
  if(Array.isArray(o.content)) return o.content.map(function(c){return c&&(c.text||c.content)||'';}).join('\n');
  if(typeof o.content==='string') return o.content;
  return JSON.stringify(o||{});
}
let raw = pickText(a);
let audit = null;
try{ const m = raw.match(/\{[\s\S]*\}/); if(m) audit = JSON.parse(m[0]); }catch(e){}
if(!audit || typeof audit!=='object' || audit.output){ audit = { overall:'غير متاح', summary:'تعذّر قراءة تقرير التدقيق المستقل', items:[] }; }
