try{
  let raw=''; try{ raw=(($('تجهيز الموجز').first().json.urls)||($('تجهيز الموجز').first().json.sources)||'')+''; }catch(e){}
  const found=(raw.match(/https?:\/\/[^\s,|\"'<>]+/g)||[]);
