  for(const u of uniq){
    let host=''; try{ const hm=u.match(/^https?:\/\/([^\/?#]+)/i); if(hm) host=hm[1].replace(/^www\./,'').toLowerCase(); }catch(e){}
    const approved=APPROVED.some(function(dn){return host===dn||host.endsWith('.'+dn);});
    let ok=null, code=null;
    if(H){ try{ const res=await H.httpRequest({method:'GET',url:u,timeout:8000,returnFullResponse:true,ignoreHttpStatusErrors:true,headers:{'User-Agent':'Mozilla/5.0'}}); code=res.statusCode||0; ok=(code>=200&&code<400); }catch(e){ code=-1; ok=false; } }
    lc.results.push({url:u,host:host,approved:approved,ok:ok,code:code});
  }
  lc.checked=lc.results.length;
  lc.live=lc.results.filter(function(r){return r.ok===true;}).length;
  lc.dead=lc.results.filter(function(r){return r.ok===false;}).length;
  lc.offdomain=lc.results.filter(function(r){return !r.approved;}).length;
