function findFutureDates(text) {
  const t = normDigits(text); const found = [];
  const re = /(20\d{2})[\/\-.](\d{1,2})[\/\-.](\d{1,2})|(\d{1,2})[\/\-.](\d{1,2})[\/\-.](20\d{2})/g;
