    if (m[1]) { y = +m[1]; mo = +m[2]; d = +m[3]; } else { d = +m[4]; mo = +m[5]; y = +m[6]; }
    const dt = new Date(y, mo - 1, d);
    if (!isNaN(dt) && dt.getTime() > now) found.push(m[0]);
