    add(`CRT-${n}-DATE`, n, "تاريخ مستقبلي", "fail", `التواريخ: ${fut.join("، ")}`, "critical", "حذفه أو (n.d.)", "writer");
  else
    add(`CRT-${n}-DATE`, n, "فحص التواريخ", "pass", "لا تواريخ مستقبلية", "minor", "", "none");
  const items = slideItems(s);
  if (!isRefs && items.length > CONFIG.maxItemsPerSlide)
    add(`CRT-${n}-CNT`, n, "عدد العناصر يتجاوز القالب", "fail", `${items.length} والحد ${CONFIG.maxItemsPerSlide}`, "major", "دمج أو حذف عناصر", "writer");
  else
