      add(`CRT-${n}-LEN${bi + 1}`, n, "عنصر أطول من الحد", "fail", `${w} كلمة والحد ${CONFIG.maxWordsPerBullet}: «${b.slice(0, 40)}…»`, "major", "اختصار العنصر", "writer");
  });
  if (wordCount(title) > CONFIG.maxTitleWords)
