// ⚖️ رئيس اللجنة — حكم حتمي — مُكيَّف على المنظومة الحية
// يقرأ: الحاسمة + المصادر + السلامة + اللغة + مدقّق التحريف (_verify)
// الأوزان: حاسمة 25٪ | مصادر 20٪ | سلامة 18٪ | عدائي 15٪ | تحريف 12٪ | لغة 10٪ (المرحلة ب)

function extractText(o) {
  // يدعم كل صيغ عقد الـ AI: نص مباشر، output[].content[].text (Responses API)، message.content، choices
  if (o == null) return '';
  if (typeof o === 'string') return o;
  if (Array.isArray(o)) return o.map(extractText).filter(Boolean).join('\n');
  if (typeof o !== 'object') return String(o);
  if (typeof o.text === 'string') return o.text;
  for (const k of ['output', 'content', 'message', 'choices', 'text']) {
    if (o[k] != null) { const t = extractText(o[k]); if (t) return t; }
  }
  return '';
}
function cleanupJSON(rawObj) {
  const raw = extractText(rawObj) || JSON.stringify(rawObj);
  const clean = String(raw).replace(/```json/gi, "").replace(/```/g, "").trim();
  try {
    const m = clean.match(/\{[\s\S]*\}/);
    return JSON.parse(m ? m[0] : clean);
  } catch (e) { return { auditor: "unknown", parse_error: true, raw: clean.slice(0, 500) }; }
}

const deck     = $('مدقّق التحريف').first().json;   // العرض + _verify
const critical = $('🔴 الفحوصات الحاسمة (كود)').first().json;
const sources  = cleanupJSON($('🟠 مدقق المصادر (AI)').first().json);
const safety   = cleanupJSON($('🟡 مدقق السلامة (AI)').first().json);
const language = cleanupJSON($('🔵 المدقق اللغوي (AI)').first().json);
let adversarial = cleanupJSON($('🗡️ المدقق العدائي (AI)').first().json);
if (!adversarial || adversarial.parse_error || !Array.isArray(adversarial.checks)) {
  adversarial = { auditor: 'adversarial_ai', auditor_name: 'المدقق العدائي', coverage: { complete: true }, checks: [], score: 6, verdict: 'pass', notes: '⚠️ تعذر تحليل مخرجات المدقق العدائي — دُرِّجت درجة محايدة (6)' };
}

// تطبيع الدرجات: بعض المدققين يرجعون 0-100 بدل 0-10
for (const rep of [sources, safety, language, adversarial]) {
  if (rep && typeof rep.score === 'number' && rep.score > 10) rep.score = Math.round(rep.score) / 10;
}

// تقرير التحريف من _verify (كود حتمي موجود مسبقًا في المنظومة)
const v = deck._verify || { ok: true, score: 100, unverified: [] };
const tamper = {
  auditor: 'tamper_code', auditor_name: 'مدقّق التحريف',
  coverage: { complete: true },
  checks: (v.unverified || []).map((num, i) => ({
