if (!reports.__guarded) {
  reports.__guarded = true;
  const _exempt = new Set(['refs', 'references', 'sources', 'cover', 'المصادر', 'المراجع']);
  (deck.slides || []).forEach(s => {
    if (/^(refs|references|sources|cover|مصادر)$/i.test(String(s.type || ''))) {
      if (s.id != null) _exempt.add(String(s.id).trim());
    }
  });
  for (const k of ['sources', 'safety', 'language', 'adversarial']) {
    const rep = reports[k];
    if (!rep || !Array.isArray(rep.checks)) continue;
    rep.checks = rep.checks.filter(c => {
      const sl = String(c.slide || '').trim();
      return !_exempt.has(sl) && !_exempt.has(sl.toLowerCase());
    });
    const crit = rep.checks.some(c => c.result === 'fail' && c.severity === 'critical');
    const maj = rep.checks.some(c => c.result === 'fail' && (c.severity === 'major' || !c.severity));
    rep.verdict = crit ? ((k === 'language' || k === 'adversarial') ? 'changes' : 'reject') : (maj ? 'changes' : 'pass');
  }
}

// ١) اكتمال التغطية (مدققو AI الثلاثة + الحاسمة)
const coverageOk = [critical, sources, safety, language].every(
  r => r && !r.parse_error && r.coverage && r.coverage.complete === true
);
if (!coverageOk) {
  const missing = ['critical', 'sources', 'safety', 'language']
    .filter(k => { const r = reports[k]; return !r || r.parse_error || !r.coverage || r.coverage.complete !== true; })
    .join(', ');
  return [{ json: Object.assign({}, deck, {
    content_ok: false, qa_passed: false, revision_count,
    escalate_to_human: false, revision_notes: [],
    committee: { verdict: 'reject', score: 0, veto_source: 'coverage_incomplete',
      notes: `تغطية غير مكتملة (${missing}) — لا يمكن إصدار حكم` }
  }) }];
}

// ٢) الفيتو
let veto = null;
if (critical.verdict === 'fail') veto = 'reject';
else if (safety.verdict === 'reject') veto = 'reject';
else if (sources.verdict === 'reject') veto = 'reject';
else if (safety.verdict === 'changes' || sources.verdict === 'changes' || tamper.verdict === 'changes') veto = 'changes';

// ٣) الدرجة الموزونة
const score =
  (critical.score || 0) * 0.25 + (sources.score || 0) * 0.20 +
  (safety.score   || 0) * 0.18 + (adversarial.score || 0) * 0.15 +
  (tamper.score   || 0) * 0.12 + (language.score || 0) * 0.10;

// ٤) الحكم
let verdict;
if (veto === 'reject') verdict = 'reject';
else if (veto === 'changes') verdict = 'changes';
else if (score >= 8.5) verdict = 'pass';
else if (score >= 6.0) verdict = 'changes';
else verdict = 'reject';

// 📏 عدادات القياس (المرحلة ب): عمق المحتوى والتنويع — حتمي
const _slidesAll = Array.isArray(deck.slides) ? deck.slides : [];
const _contentSlides = _slidesAll.filter(s => !/^(section|refs|references|sources|cover|مصادر)$/i.test(String(s.type || '')));
const _sectionSlides = _slidesAll.filter(s => String(s.type || '').toLowerCase() === 'section');
const _titlesArr = _contentSlides.map(s => String(s.title || '').trim()).filter(Boolean);
const _dupTitles = _titlesArr.length - new Set(_titlesArr).size;
const _dupList = _titlesArr.filter(function(t,i){return _titlesArr.indexOf(t)!==i;});
const _sectionLimit = Math.max(2, Math.ceil(_contentSlides.length / 5));
const metrics = {
  slides_total: _slidesAll.length,
  content_slides: _contentSlides.length,
  section_count: _sectionSlides.length,
  section_limit: _sectionLimit,
  section_overuse: _sectionSlides.length > _sectionLimit,
  duplicate_titles: _dupTitles,
  duplicate_list: _dupList
};
if (verdict === 'pass' && (metrics.section_overuse || metrics.duplicate_titles > 1)) verdict = 'changes';

// ٥) التصعيد بعد 3 دورات
const escalate_to_human = verdict !== 'pass' && revision_count >= 3;
if (escalate_to_human) verdict = 'reject';

// ٦) ملاحظات المراجعة مرتبة بالخطورة
const sev = { critical: 0, major: 1, minor: 2 };
const revision_notes = [];
if (verdict !== 'pass') {
  Object.values(reports).forEach(rep => {
    (rep.checks || [])
      .filter(c => c.result === 'fail' || c.result === 'warn' || c.result === 'warning')
      .forEach(c => revision_notes.push({
