}

// 📏 ملاحظات العدادات
if (verdict !== 'pass' && metrics.section_overuse) {
  revision_notes.push({ source: 'عدادات الرئيس', slide: '-', issue: `فواصل أقسام أكثر من اللازم (${metrics.section_count} فاصل مقابل ${metrics.content_slides} شريحة محتوى)`, evidence: `الحد المقبول ${metrics.section_limit}`, fix: 'قلّل فواصل الأقسام وادمجها لصالح محتوى أعمق وتنويع أكبر', severity: 'major', route_to: 'writer' });
}
if (verdict !== 'pass' && metrics.duplicate_titles > 0) {
  revision_notes.push({ source: 'عدادات الرئيس', slide: '-', issue: `${metrics.duplicate_titles} عنوان مكرر: «${(metrics.duplicate_list||[]).join('» و«')}»`, evidence: 'عناوين متطابقة حرفيًا', fix: `غيّر عنوان إحدى الشرائح التي تحمل: ${(metrics.duplicate_list||[]).join('، ')}`, severity: metrics.duplicate_titles > 1 ? 'major' : 'minor', route_to: 'writer' });
}

// ٧) الملاحظة الختامية
let veto_source = null;
if (veto) {
  if (critical.verdict === 'fail') veto_source = 'critical_code';
  else if (safety.verdict !== 'pass') veto_source = 'safety_ai';
  else if (sources.verdict !== 'pass') veto_source = 'sources_ai';
  else if (tamper.verdict !== 'pass') veto_source = 'tamper_code';
}
const fc = { critical: 0, major: 0, minor: 0 };
revision_notes.forEach(n => { fc[n.severity] = (fc[n.severity] || 0) + 1; });
const rs = Math.round(score * 10) / 10;
let notes;
if (escalate_to_human) notes = `🚨 تصعيد إلى المحكّم البشري — ${revision_count} دورات مراجعة بدون اعتماد`;
else if (verdict === 'pass') notes = `✅ اعتُمد العرض — الدرجة الموزونة: ${rs}/10`;
else {
  const parts = [];
  if (veto) parts.push('فيتو نشط');
  if (fc.critical) parts.push(`${fc.critical} حاسمة`);
  if (fc.major) parts.push(`${fc.major} كبيرة`);
  if (fc.minor) parts.push(`${fc.minor} بسيطة`);
