// 📐 مطابقة القالب — تقسيم حتمي للشرائح المتجاوزة (بلا AI، بلا فقدان محتوى)
// حدود القالب الفعلية من build.js: emergency=4 | cards/cardsDesc=6 | البقية=8
const deck = $input.first().json;
const LIMITS = { emergency: 4, cards: 6, cardsDesc: 6, 'default': 8 };
const LIST_FIELDS = ['items', 'points', 'steps', 'cards', 'scenarios', 'qa'];
const isRefs = s => /^(refs|references|sources|closing|مصادر)$/i.test(String(s.type||'')) || /^(المصادر|المراجع)/.test(String(s.title||''));
const outSlides = [];
for (const s of (deck.slides || [])) {
  if (!s || typeof s !== 'object' || isRefs(s)) { outSlides.push(s); continue; }
  const limit = LIMITS[s.type] || LIMITS['default'];
  const field = LIST_FIELDS.find(f => Array.isArray(s[f]) && s[f].length > limit);
  if (!field) { outSlides.push(s); continue; }
  const arr = s[field];
  const chunks = [];
  for (let i = 0; i < arr.length; i += limit) chunks.push(arr.slice(i, i + limit));
  chunks.forEach((chunk, ci) => {
    const clone = JSON.parse(JSON.stringify(s));
    clone[field] = chunk;
    if (ci > 0) {
      clone.title = String(s.title || '') + ' (تتمة)';
      // شرائح التتمة للطوارئ تصير compact — دائرة 999 لا تتكرر
      if (s.type === 'emergency') { clone.type = 'compact'; delete clone.exampleText; delete clone.exampleLabel; }
    }
    outSlides.push(clone);
  });
}
return [{ json: Object.assign({}, deck, { slides: outSlides }) }];

// ⚖️ بوابة الترجمة — فحص حتمي (ISO 18587: الترجمة الآلية مسودة تُراجع إلزاميًا)
function extractText(o) {
  if (o == null) return '';
  if (typeof o === 'string') return o;
  if (Array.isArray(o)) return o.map(extractText).filter(Boolean).join('\n');
  if (typeof o !== 'object') return String(o);
  if (typeof o.text === 'string') return o.text;
  for (const k of ['output', 'content', 'message', 'choices', 'text']) {
    if (o[k] != null) { const t = extractText(o[k]); if (t) return t; }
  }
  return '';
}
function cleanupJSON(rawObj) {
  const raw = extractText(rawObj) || JSON.stringify(rawObj);
  const clean = String(raw).replace(/```json/gi, "").replace(/```/g, "").trim();
  try { const m = clean.match(/\{[\s\S]*\}/); return JSON.parse(m ? m[0] : clean); }
  catch (e) { return { parse_error: true, raw: clean.slice(0, 400) }; }
}
const LIST_FIELDS = ['items', 'points', 'steps', 'cards', 'scenarios', 'qa', 'do', 'dont', 'pairs', 'groups', 'when', 'say', 'report', 'safe_return', 'disposal', 'sources'];
const isRefs = s => /^(refs|references|sources|closing|مصادر)$/i.test(String((s && s.type) || ''));
function slideTexts(s) {
  const out = [];
  const push = v => { if (v != null && typeof v !== 'object' && String(v).trim()) out.push(String(v)); };
  const arr = v => Array.isArray(v) ? v : (v == null ? [] : [v]);
  ['title','name','desc','description','text','tagline','exampleText','quote','subtitle','scenario','main_message','stat','stat_meaning','curiosity_hook','truth_opener','critical_dont','empowerment_line','interaction_question','scenario_callback','scenario_close','surprise_fact'].forEach(f => push(s[f]));
  LIST_FIELDS.forEach(f => arr(s[f]).forEach(v => {
    if (v && typeof v === 'object') ['name','title','desc','text','q','a','question','answer','instead_of','do_this','group','behavior'].forEach(k => push(v[k]));
    else push(v);
  }));
  return out;
}
const normDigits = t => String(t == null ? '' : t).replace(/[٠-٩]/g, d => String('٠١٢٣٤٥٦٧٨٩'.indexOf(d)));
const digitsOf = deck => {
  const bag = {};
  (deck.slides || []).forEach(s => slideTexts(s).forEach(t => {
    (normDigits(t).match(/\d+/g) || []).forEach(n => { bag[n] = (bag[n] || 0) + 1; });
  }));
  return bag;
};

const orig  = $('⚖️ رئيس اللجنة').first().json;
const trans = cleanupJSON($('🌐 المترجم (AI)').first().json);
const audit = cleanupJSON($('🔍 مدقق الترجمة (AI)').first().json);
let t_retry = 0;
try { t_retry = Number($('🔁 عدّاد الترجمة').first().json.t_retry) || 0; } catch (e) {}

const notes = [];
const add = (issue, evidence, severity, fix) => notes.push({ source: 'بوابة الترجمة (كود)', slide: '-', issue, evidence, severity, fix: fix || '', route_to: 'translator' });

// ─── فحوصات حتمية ───
if (trans.parse_error) add('تعذّر تحليل JSON الترجمة', String(trans.raw).slice(0, 120), 'critical', 'أخرج JSON خام فقط');
const oS = orig.slides || [], tS = trans.slides || [];
if (!trans.parse_error) {
  if (tS.length !== oS.length)
    add('عدد الشرائح غير مطابق', `الأصل ${oS.length} والترجمة ${tS.length}`, 'critical', 'ترجمة كل شريحة 1:1 دون دمج أو حذف');
  const n = Math.min(oS.length, tS.length);
  for (let i = 0; i < n; i++) {
    for (const f of LIST_FIELDS) {
      const a = Array.isArray(oS[i][f]) ? oS[i][f].length : 0;
      const b = Array.isArray(tS[i][f]) ? tS[i][f].length : 0;
      if (a !== b) add(`شريحة ${oS[i].id || i + 1}: عدد عناصر ${f} غير مطابق`, `الأصل ${a} والترجمة ${b}`, 'critical', 'انقل كل العناصر دون حذف أو إضافة');
    }
    const origPending = /MISSING_|\[[^\]]*\]/.test(JSON.stringify(oS[i] || {})); // شريحة ناقصة بالتصميم (بانتظار وكيل البحث)
    if (!isRefs(tS[i]) && !origPending) {
      const arb = slideTexts(tS[i]).filter(t => !/MISSING_/i.test(t)).join(' ').replace(/\[[^\]]*\]/g, ' ').match(/[؀-ۿ]{2,}/); // العلامات النظامية MISSING_ والأقواس [] تُستثنى
      if (arb) add(`شريحة ${tS[i].id || i + 1}: نص عربي متبقٍ في الترجمة`, `«${arb[0]}»`, 'critical', 'ترجم النص المتبقي');
    }
  }
