  const od = digitsOf(orig), td = digitsOf(trans);
  for (const [num, cnt] of Object.entries(od)) {
    if ((td[num] || 0) < cnt) add(`الرقم ${num} ناقص في الترجمة`, `ورد ${cnt} مرة في الأصل و${td[num] || 0} في الترجمة`, 'critical', 'أعد الرقم كما في الأصل');
  }
}
// ─── تقرير المدقق المستقل ───
let auditScore = null;
if (audit.parse_error) {
  add('تعذّر قراءة تقرير مدقق الترجمة', String(audit.raw).slice(0, 100), 'major', 'إعادة الدورة');
} else {
  // جدار حماية حتمي: فحوصات العلامات النظامية MISSING_ ليست أخطاء (بالتصميم — بانتظار وكيل البحث)
  if (Array.isArray(audit.checks)) {
    const sys = c => /MISSING_/i.test(String((c && c.claim) || '') + ' ' + String((c && c.evidence) || '') + ' ' + String((c && c.fix) || ''));
    const hadSys = audit.checks.some(sys);
    audit.checks = audit.checks.filter(c => !sys(c));
    if (hadSys && audit.verdict === 'reject' && !audit.checks.some(c => c.result === 'fail' && c.severity === 'critical')) {
      audit.verdict = audit.checks.some(c => c.result === 'fail') ? 'changes' : 'pass';
      audit.notes = (audit.notes || '') + ' [جدار الحماية: أُسقطت اعتراضات العلامات النظامية وأُعيد الحكم]';
    }
  }
  auditScore = audit.score;
  (audit.checks || []).filter(c => c.result === 'fail' || c.result === 'warn')
    .forEach(c => notes.push({ source: audit.auditor_name || 'مدقق الترجمة', slide: c.slide, issue: c.claim, evidence: c.evidence, severity: c.severity || 'minor', fix: c.fix || '', route_to: 'translator' }));
  if (audit.verdict === 'reject') add('فيتو مدقق الترجمة', audit.notes || '', 'critical', '');
}
const hardFails = notes.filter(x => x.severity === 'critical' || x.severity === 'major').length;
const ok = hardFails === 0;
const escalate_translation = !ok && t_retry >= 2;

if (ok) {
  return [{ json: Object.assign({}, trans, {
    language: trans.language || 'en', direction: trans.direction || 'ltr',
    translation_ok: true, t_retry,
    translation_report: { score: auditScore, notes: `✅ اعتُمدت الترجمة — ${notes.length} ملاحظة بسيطة`, new_terms: trans.new_terms || [] }
  }) }];
}
return [{ json: Object.assign({}, orig, {
  translation_ok: false, t_retry, escalate_translation,
  translation_notes: notes.sort((a, b) => (a.severity === 'critical' ? 0 : 1) - (b.severity === 'critical' ? 0 : 1)),
  translation_report: { score: auditScore, notes: `❌ ${hardFails} مخالفة — ${escalate_translation ? 'تصعيد للمحكّم' : 'إعادة للمترجم'}` }
}) }];

// 🔁 عدّاد الترجمة — دورتا إصلاح كحد أقصى ثم تصعيد
const j = $input.first().json;
const c = (Number(j.t_retry) || 0) + 1;
return [{ json: { ...j, t_retry: c, escalate: j.escalate_translation === true || c > 2 } }];

// 🧮 فحص الهيكل — حتمي بعد دفعة 0
function extractText(o){if(o==null)return '';if(typeof o==='string')return o;if(Array.isArray(o))return o.map(extractText).filter(Boolean).join('\n');if(typeof o!=='object')return String(o);if(typeof o.text==='string')return o.text;for(const k of ['output','content','message','choices','text']){if(o[k]!=null){const t=extractText(o[k]);if(t)return t;}}return '';}
const raw = extractText($input.first().json) || JSON.stringify($input.first().json);
let m = null; try { const x = raw.replace(/```json/gi,'').replace(/```/g,'').match(/\{[\s\S]*\}/); m = JSON.parse(x ? x[0] : raw); } catch(e) {}
const wc = t => String(t||'').trim().split(/\s+/).filter(Boolean).length;
let h_try = 0; try { h_try = Number($('🔁 عدّاد الهيكل').first().json.h_try) || 0; } catch(e) {}
const h_notes = [];
if (!m) h_notes.push({slide_n:0, field:'json', reason:'تعذر تحليل هيكل دفعة 0', rule_ref:'هيكل'});
else {
  if (!m.main_message) h_notes.push({slide_n:3, field:'main_message', reason:'الرسالة مفقودة', rule_ref:'بند 7'});
  else if (wc(m.main_message) > 15) h_notes.push({slide_n:3, field:'main_message', reason:`الرسالة ${wc(m.main_message)} كلمة والحد 15`, rule_ref:'بند 7'});
  const ts = m.titles || [];
  if (ts.length !== 15) h_notes.push({slide_n:0, field:'titles', reason:`${ts.length} عنوانًا والمطلوب 15`, rule_ref:'بند 1'});
  ts.forEach((t,i)=>{ if (wc(t) > 8) h_notes.push({slide_n:i+1, field:'title', reason:`العنوان ${wc(t)} كلمة والحد 8`, rule_ref:'بند 3'}); });
  if (!m.framing_scenario || !m.framing_scenario.text) h_notes.push({slide_n:3, field:'framing_scenario', reason:'السيناريو الإطاري مفقود', rule_ref:'بند 8'});
  const hooks = m.curiosity_hooks || {};
  for (const k of ['s3','s6','s9']) if (!hooks[k]) h_notes.push({slide_n:Number(k.slice(1)), field:'curiosity_hook', reason:'سطر الفضول مفقود', rule_ref:'بند 12'});
}
const h_ok = h_notes.length === 0;
return [{ json: { h_ok, h_try, h_notes, h_pass: h_ok || h_try >= 2 } }];

// 🔁 عدّاد الهيكل
const j = $input.first().json;
return [{ json: { ...j, h_try: (Number(j.h_try) || 0) + 1 } }];

// 🧩 تجميع الدفعات + 🗺️ التحويل لأشكال العرض المعتمدة — عقدة Code واحدة
// المدخل: مخرجات دفعة 0 و1 و2 و3 عبر $() — المخرج: {std: مستند v1.1 كامل, deck: بصيغة البنّاء}
function extractText(o) {
  if (o == null) return '';
  if (typeof o === 'string') return o;
  if (Array.isArray(o)) return o.map(extractText).filter(Boolean).join('\n');
  if (typeof o !== 'object') return String(o);
  if (typeof o.text === 'string') return o.text;
  for (const k of ['output', 'content', 'message', 'choices', 'text']) {
    if (o[k] != null) { const t = extractText(o[k]); if (t) return t; }
  }
  return '';
}
function cleanJSON(rawObj, wantArray) {
  const raw = extractText(rawObj) || JSON.stringify(rawObj);
  const clean = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
  try {
    const m = clean.match(wantArray ? /\[[\s\S]*\]/ : /\{[\s\S]*\}/);
    return JSON.parse(m ? m[0] : clean);
  } catch (e) { return null; }
}

const meta0 = cleanJSON($('✍️ دفعة 0 — الهيكل').first().json, false) || {};
const b1 = cleanJSON($('✍️ دفعة 1 — اعرف (ش1-6)').first().json, true) || [];
const b2 = cleanJSON($('✍️ دفعة 2 — تجنّب (ش7-9)').first().json, true) || [];
const b3 = cleanJSON($('✍️ دفعة 3 — تصرّف وما بعد (ش10-15)').first().json, true) || [];
const grounding = $('دمج التأصيل').first().json || {};

const slides = [].concat(b1, b2, b3).filter(s => s && typeof s === 'object')
  .sort((a, b) => (a.n || 0) - (b.n || 0));

const std = {
  topic_code: grounding.topic_code || '',
  title_ar: grounding.title || (meta0.title || '').replace(/^الغلاف$/, '') || ((slides[0] && slides[0].title !== 'الغلاف') ? slides[0].title : '') || '',
  classification: 'عام',
  audience: meta0.audience || grounding.audience || 'عام',
  season: meta0.season || 'على مدار السنة',
  main_message: meta0.main_message || '',
  framing_scenario: meta0.framing_scenario || { text: '', open_on: 3, callback_on: 10, close_on: 14 },
  behavioral_arc: ['اعرف', 'تجنب', 'تصرف', 'ما بعد'],
  slides
};

// ─── توحيد حتمي: الرسالة الرئيسية حرفيًا في ش3 وش14 (تطبيق بند 7 من المعيار) ───
const mm = std.main_message;
if (mm) {
  const s3x = slides.find(s => s && s.n === 3);
  if (s3x) s3x.main_message = mm;
  const s14x = slides.find(s => s && s.n === 14);
  if (s14x) {
    const items = Array.isArray(s14x.items) ? s14x.items : [];
    if (!items.includes(mm)) { if (items.length) items[0] = mm; else items.push(mm); }
    s14x.items = items;
    s14x.repeat_main_message = true;
    s14x.main_message = mm;
  }
}

// ─── تمرير الأنواع الأصلية (معيار v1.1) — البنّاء v3 يرسمها مباشرة ───
const deck = {
  code: std.topic_code, title: std.title_ar, title_ar: std.title_ar,
  language: grounding.language || 'ar',
  audience: std.audience, season: std.season,
  main_message: std.main_message, framing_scenario: std.framing_scenario,
  icon: 'FaShieldAlt',
  slides: slides
};
return [{ json: { std, deck, output: JSON.stringify(deck), topic_code: std.topic_code } }];

// 🧾 بوابة المعيار v1.1 — نقل حرفي لفحوص validator.py إلى n8n (حتمي، بلا AI)
const EXPECTED = ["cover","objectives","main_message_why","definition","causes",
  "warning_signs","prevention_1","prevention_2","mistake_alternatives",
  "response_steps","special_groups","emergency_999","after_incident",
  "key_messages","sources"];
const wc = t => String(t || '').trim().split(/\s+/).filter(Boolean).length;
const passthrough0 = $('🧩 تجميع وتحويل v1.1').first().json;
const d = passthrough0.std;
const official = $input.first().json || {};
const passthrough = passthrough0;

let t_std = 0;
try { t_std = Number($('🔁 عدّاد المعيار').first().json.t_std) || 0; } catch (e) {}

const notes = [];
const add = (slide_n, field, reason, rule_ref) => notes.push({ slide_n, field, reason, rule_ref });

const slides = Array.isArray(d && d.slides) ? d.slides : [];
const byN = {}; slides.forEach(s => { byN[s.n] = s; });
const g = n => byN[n] || {};

const seq = slides.map(s => s.type);
if (JSON.stringify(seq) !== JSON.stringify(EXPECTED))
  add(0, 'slides', 'التسلسل لا يطابق الـ 15 المعياري: ' + seq.join(','), 'بند 1');

if (!g(4).text) add(4, 'text', 'تعريف الخطر فارغ', 'بند 2');
if (!g(3).stat) add(3, 'stat', 'إحصائية ش3 مفقودة', 'بند 2/4');
for (const [n, f] of [[5,'items'],[6,'items'],[7,'items'],[10,'steps']])
  if (!Array.isArray(g(n)[f]) || !g(n)[f].length) add(n, f, 'قائمة أساسية فارغة', 'بند 2');
if (!(g(13).report || []).length && !(g(13).safe_return || []).length)
  add(13, 'report', 'ما بعد الحادث فارغ', 'بند 2');

const LISTS = ['items','when','say','report','safe_return','disposal'];
for (const s of slides) {
  if (s.title && wc(s.title) > 8) add(s.n, 'title', `العنوان ${wc(s.title)} كلمة والحد 8`, 'بند 3');
  for (const lk of LISTS) {
    const lst = s[lk] || [];
    if (lst.length > 5) add(s.n, lk, `${lst.length} نقاط والحد 5`, 'بند 3');
    for (const b of lst) if (wc(b) > 12) add(s.n, lk, `نقطة ${wc(b)} كلمة والحد 12: «${String(b).slice(0,30)}…»`, 'بند 3');
  }
  const steps = s.steps || [];
  if (steps.length > 5) add(s.n, 'steps', `${steps.length} خطوات والحد 5`, 'بند 3');
  for (const b of steps) if (wc(b) > 14) add(s.n, 'steps', `خطوة ${wc(b)} كلمة والحد 14 (استثناء معتمد)`, 'بند 3+استثناء');
  for (const p of s.pairs || []) for (const v of Object.values(p)) if (wc(v) > 12) add(s.n, 'pairs', `زوج ${wc(v)} كلمة`, 'بند 3');
  for (const gr of s.groups || []) if (wc(gr.behavior || '') > 12) add(s.n, 'groups', `سلوك فئة ${wc(gr.behavior)} كلمة`, 'بند 3');
}

const s3 = g(3);
if (s3.stat) {
  const src = s3.source || {};
  if (!src.name || !src.year) add(3, 'source', 'الإحصائية بلا مصدر أو سنة', 'بند 4');
  if (!s3.stat_meaning) add(3, 'stat_meaning', 'جملة «أي إن...» مفقودة', 'بند 4');
}

const risk = s3.risk || {};
if (!risk.likelihood || !risk.severity) add(3, 'risk', 'الاحتمالية أو الشدة مفقودة', 'بند 5');

const allText = JSON.stringify(d);
const badNum = allText.match(/(?:^|[^\d])(911|112|998|997|996|995)(?:[^\d]|$)/);
if (badNum) add(0, 'emergency', `رقم طوارئ مخالف: ${badNum[1]}`, 'بند 6');
if (/ذوي الاحتياجات|ذوي الإعاقة|المعاقين/.test(allText)) add(0, 'terminology', 'المصطلح المعتمد: أصحاب الهمم', 'بند 6');

const mm = d.main_message || '';
if (!mm) add(3, 'main_message', 'الرسالة الرئيسية مفقودة', 'بند 7');
else {
  if (wc(mm) > 15) add(3, 'main_message', `الرسالة ${wc(mm)} كلمة والحد 15`, 'بند 7');
  const s14txt = JSON.stringify(g(14));
  if (!(g(14).repeat_main_message === true || s14txt.includes(mm))) add(14, 'main_message', 'الرسالة غير مكررة حرفيًا في الخلاصة', 'بند 7');
}

const fs = d.framing_scenario || {};
if (!fs.text || !s3.scenario) add(3, 'scenario', 'السيناريو الإطاري غير مفتوح في ش3', 'بند 8');
if (!g(10).scenario_callback) add(10, 'scenario_callback', 'استدعاء السيناريو مفقود', 'بند 8');
if (!g(14).scenario_close) add(14, 'scenario_close', 'إغلاق السيناريو مفقود', 'بند 8');

if (!g(7).empowerment_line) add(7, 'empowerment_line', 'عبارة التمكين مفقودة', 'بند 9');
let strayDont = 0;
for (const s of slides) {
  if ([9].includes(s.n)) continue;
  for (const lk of ['items','steps','when','say','report','safe_return','disposal'])
    for (const b of s[lk] || []) if (/^لا\s+ت/.test(String(b).trim())) strayDont++;
}
if (strayDont > 0) add(0, 'framing', `${strayDont} نهي خارج التحذير الحرج — الصياغة بالإيجاب`, 'بند 9');
if (!g(9).critical_dont) add(9, 'critical_dont', 'التحذير الحرج مفقود', 'بند 9');

if (!g(6).interaction_question) add(6, 'interaction_question', 'سؤال ش6 مفقود', 'بند 10');
if (!g(11).interaction_question) add(11, 'interaction_question', 'سؤال ش11 مفقود', 'بند 10');
for (const n of [3, 6, 9]) if (!g(n).curiosity_hook) add(n, 'curiosity_hook', 'سطر الفضول مفقود', 'بند 10');

for (const n of [3, 4, 10]) { const v = g(n).visual || {}; if (!v.kind && !v.desc) add(n, 'visual', 'الدليل البصري غير محدد', 'بند 11'); }

const pats = slides.map(s => s.pattern || 'text');
for (let i = 2; i < pats.length; i++)
  if (pats[i] === pats[i-1] && pats[i] === pats[i-2]) { add(slides[i].n, 'pattern', `3 شرائح متتالية بنمط ${pats[i]}`, 'بند 12'); break; }

if (!d.audience) add(0, 'audience', 'حقل الجمهور فارغ', 'بند 13');
if (!d.season) add(0, 'season', 'حقل الموسم فارغ', 'بند 13');

const s15 = g(15);
if (!Array.isArray(s15.iso26000) || !s15.iso26000.length) add(15, 'iso26000', 'بنود ISO 26000 مفقودة', 'بند 14');
if (!Array.isArray(s15.sources) || !s15.sources.length || !s15.sources[0].name) add(15, 'sources', 'قائمة المصادر فارغة', 'بند 14');
(s15.sources || []).forEach(x => { if (!x || !x.name) { add(15, 'sources', 'مصدر بلا جهة ناشرة (APA)', 'بند 14'); return; } if (!/^(19|20)\d\d$/.test(String(x.year || ''))) add(15, 'sources', 'مصدر «' + x.name + '» بلا سنة رقمية صالحة (APA)', 'بند 14'); });

// المدقق الرسمي validator.py (مصدر الحقيقة) — اتحاد الأشد صرامة
if (official && Array.isArray(official.fails)) {
  official.fails.forEach(f => add(0, 'validator.py', String(f).replace(/^❌\s*/, ''), 'المدقق الرسمي'));
}
const std_ok = notes.length === 0;
const escalate_std = !std_ok && t_std >= 2;
return [{ json: Object.assign({}, passthrough, {
  std_ok, t_std, escalate_std,
  std_notes: notes,
  std_report: std_ok ? '✅ المعيار v1.1: 16/16' : `❌ ${notes.length} مخالفة معيار — ${escalate_std ? 'تصعيد' : 'إعادة كتابة موجهة'}`
}) }];

// 🔁 عدّاد المعيار — دورتان ثم تصعيد
const j = $input.first().json;
const c = (Number(j.t_std) || 0) + 1;
return [{ json: { ...j, t_std: c, escalate: j.escalate_std === true || c > 2 } }];

// 🧷 دمج العرض مع رابط جلسة الرفع — الملف سيُرفع من Render مباشرة
const sess = $input.first().json;
if (!sess || !sess.uploadUrl) throw new Error('لم تصل جلسة رفع OneDrive');
let deck = null;
try { const t = $('✅ الترجمة معتمدة؟').first().json; if (t && t.slides) deck = t; } catch (e) {}
if (!deck) { const a = $('🌍 يحتاج ترجمة؟').first().json; if (a && a.slides) deck = a; }
if (!deck) throw new Error('تعذر إيجاد العرض قبل جلسة الرفع');
return [{ json: Object.assign({}, deck, { upload_url: sess.uploadUrl }) }];

