// 📈 تسجيل تحليلات التشغيل — بيانات حقيقية لكل عرض
const req=$('تنظيم بيانات الطلب').first().json;
let ch={}; try{ch=$('⚖️ رئيس اللجنة').first().json;}catch(e){}
const comm=ch.committee||{}; const bd=comm.breakdown||{};
const sc=k=>bd[k]&&typeof bd[k].score==='number'?bd[k].score:null;
let uploaded=null; try{ const u=$('✅ التدقيق النهائي').first().json; uploaded=u&&u.uploaded===true; }catch(e){}
let cycleNotes=[];
try{ for(let ri=0;ri<8;ri++){ const its=$('⚖️ رئيس اللجنة').all(0,ri); if(!its||!its.length)break; const jj=its[0].json||{}; const tt=String(jj.revision_notes||(jj.committee&&jj.committee.notes)||'').trim(); if(tt&&cycleNotes.indexOf(tt)<0)cycleNotes.push(tt); } }catch(e){}
let risk=null, weak=null;
try{
  const deckJ=$('🧩 تجميع وتحويل v1.1').first().json||{};
  const deck=deckJ.content||deckJ.json||deckJ;
  const slides=Array.isArray(deck.slides)?deck.slides:[];
  const texts=[]; let srcs=[];
  slides.forEach(function(s){ if(!s)return;
    ['bullets','points','items','body'].forEach(function(k){ if(Array.isArray(s[k])) s[k].forEach(function(b){ texts.push(String((b&&(b.text||b.title))||b||'')); }); });
    if(s.main_message)texts.push(String(s.main_message)); if(s.subtitle)texts.push(String(s.subtitle)); if(s.stat_text)texts.push(String(s.stat_text));
    ['sources','source','refs','references'].forEach(function(k){ if(Array.isArray(s[k]))srcs=srcs.concat(s[k]); else if(s[k])srcs.push(s[k]); });
  });
  ['sources','references'].forEach(function(k){ if(Array.isArray(deck[k]))srcs=srcs.concat(deck[k]); });
  let best=0;
  texts.forEach(function(t){ if(!t)return;
    const mp=t.match(/(\d+(?:[\.,]\d+)?)\s*[%\u066A]/); let v=mp?parseFloat(mp[1])*10:0;
    const mn=t.match(/\d{3,}/); if(mn)v=Math.max(v,parseFloat(mn[0]));
    if(v>best){best=v;risk=t.slice(0,140);} });
  let oldest=null;
  srcs.forEach(function(s0){ const st=typeof s0==='string'?s0:JSON.stringify(s0);
    const ys=st.match(/20\d{2}/g); if(!ys)return; const y=Math.min.apply(null,ys.map(Number));
    if(!oldest||y<oldest.year){ const tt=typeof s0==='string'?s0:String(s0.title||s0.publisher||s0.name||st); oldest={year:y,title:tt.slice(0,90)}; } });
  if(oldest)weak=oldest;
}catch(e){}
const rec={
  at:new Date().toISOString(),
  topic:String(req.topic_code||req.new_title||''),
  pkg:String(req.package||''),
  lang:String(req.language||'ar'),
  task:String(req.task_type||''),
  rework:Number(ch.revision_count||0),
  escalated:ch.escalate_to_human===true,
  verdict: ch.escalate_to_human?'escalated':((ch.qa_passed||ch.content_ok||comm.verdict==='pass')?'approved':'done'),
  score: (typeof comm.score==='number')?comm.score:null,
  veto: comm.veto_source||null,
  notes: String((cycleNotes.join(' | ')||ch.revision_notes||comm.notes||'')).slice(0,180),
  risk_sentence:risk, weak_source:weak, breakdown:{critical:sc('critical'),sources:sc('sources'),safety:sc('safety'),tamper:sc('tamper'),language:sc('language')},
  uploaded: uploaded,
  cycleMs: req._t0?(Date.now()-Number(req._t0)):null
};
const sd=$getWorkflowStaticData('global');
sd.analytics=sd.analytics||[];
sd.analytics.push(rec);
if(sd.analytics.length>300) sd.analytics=sd.analytics.slice(-300);
return [{json:rec}];

// 📊 قراءة تحليلات مدير النظام — أعطال صريحة فقط (انهيار غير مستعاد / عيب بعد النشر)
const sd=$getWorkflowStaticData('global');
// تصفير محمي بمفتاح — يمسح سجل التشغيلات التجريبية فقط، لا يلمس الفهرس ولا الاعتمادات
let q={}; try{ q=($input.first().json.query)||{}; }catch(e){}
if(String(q.reset||'')==='ali-adcda-2026'){ const n0=(sd.analytics||[]).length; sd.analytics=[]; return [{json:{ok:true,reset:true,cleared:n0,at:new Date().toISOString()}}]; }
const log=(sd.analytics||[]).slice();
// قياس زمن مرجعي حقيقي (مقيس من التنفيذات الفعلية 2026-07-12)
const timing={
  ground:{avgMs:6905,label:'التأصيل'}, stats:{avgMs:2956,label:'وكيل الإحصائيات'}, writer:{avgMs:25227,label:'الكاتب بالدفعات'},
  gStd:{avgMs:226,label:'بوابة المعيار'}, committee:{avgMs:2704,label:'لجنة التدقيق'}, gChair:{avgMs:548,label:'الرئيس الحتمي'},
  builder:{avgMs:1516,label:'البانّي'}, upload:{avgMs:686,label:'الرفع المباشر'}, registrar:{avgMs:727,label:'التسجيل'}
};
const N=log.length;
const avg=(a)=>a.length?a.reduce((x,y)=>x+y,0)/a.length:0;
// أعطال صريحة = انهيار لم يُستعد ذاتيًا أو عيب اكتُشف بعد النشر — فقط
const hard=log.filter(x=>x.hardFail===true||x.postDefect===true);
const prod=log.filter(x=>!x.hardFail);
const withRework=prod.filter(x=>x.rework>0).length;
const escalated=prod.filter(x=>x.escalated).length;
const cyc=prod.filter(x=>x.cycleMs).map(x=>x.cycleMs);
const errPct = N? Math.round(100*hard.length/N) : 0;
function audit(k){
  const rel=prod.filter(x=>x.breakdown&&x.breakdown[k]!=null);
  const v=rel.map(x=>x.breakdown[k]);
  const bad=rel.filter(x=>x.breakdown[k]<8);
  return {avg:v.length?Math.round(avg(v)*10)/10:null,fails:bad.length,n:v.length,
    issues:bad.slice(-3).map(x=>({at:x.at,topic:x.topic,score:x.breakdown[k],
      note:(x.notes&&String(x.notes).trim())?String(x.notes).slice(0,160):('صُحّح ذاتيًا خلال '+(x.rework||0)+' دورة قبل النشر')}))};
}
const auditors={critical:audit('critical'),sources:audit('sources'),safety:audit('safety'),tamper:audit('tamper'),language:audit('language')};
const trend=log.slice(-12).map(x=>({at:x.at,sec:x.cycleMs?Math.round(x.cycleMs/1000):null,rework:x.rework||0,esc:!!x.escalated,fail:!!x.hardFail}));
const pendingArr=Array.isArray(sd.pending)?sd.pending:[];
const pendingHuman=pendingArr.filter(function(x){const st=String((x&&(x['حالة الإنتاج']||x['الحالة']))||'');return st.indexOf('انتظار')>=0||st.indexOf('مراجعة')>=0;}).length;
const lastP=prod.length?prod[prod.length-1]:null;
const approval={pendingHuman:pendingHuman,latest:lastP?{at:lastP.at,topic:lastP.topic,verdict:lastP.verdict,score:lastP.score,rework:lastP.rework||0,escalated:!!lastP.escalated,notes:lastP.notes||'',breakdown:lastP.breakdown||null,risk_sentence:lastP.risk_sentence||null,weak_source:lastP.weak_source||null}:null};
return [{json:{
  ok:true, generatedAt:new Date().toISOString(),
  liveCount:N,
  systemErrorPct: errPct,
  hardFailCount: hard.length,
  lastHardFail: hard.length? {at:hard[hard.length-1].at, topic:hard[hard.length-1].topic, reason:hard[hard.length-1].reason||''} : null,
  reworkPct: N?Math.round(100*withRework/N):null,
  escalPct: N?Math.round(100*escalated/N):null,
  avgCycleSec: cyc.length?Math.round(avg(cyc)/1000):null,
  approval, timing, auditors, trend,
  recent: log.slice(-15).reverse(),
  note: N? 'حي — الأعطال الصريحة فقط: انهيار غير مستعاد أو خطأ بعد النشر. دورات التصحيح الذاتي لا تُحسب أخطاء':'سجل نظيف بعد التصفير — بانتظار أول تشغيل إنتاجي'
}}];

// يقارن عنوان الطلب مع نتائج فهرس الـ70 موضوعًا — حتمي
const req = $('دمج التأصيل').first().json;
const res = $input.first().json || {};
const cands = Array.isArray(res.matches) ? res.matches : [];
const STOP = new Set(['في','من','على','عن','الى','إلى','مع','و','او','أو','ثم','ب','ل','ال','لل','هو','هي','ما','لا','ان','أن','عند','داخل','خلال','ضد']);
function norm(s){
  s = String(s||'').replace(/[\u064B-\u0652\u0640]/g,'');
  s = s.replace(/[أإآ]/g,'ا').replace(/ى/g,'ي').replace(/ؤ/g,'و').replace(/ئ/g,'ي').replace(/ة/g,'ه');
  s = s.replace(/(.)\1+/g,'$1');
  return s.trim();
}
function toks(s){ return norm(s).split(/[^\u0621-\u064Aa-zA-Z0-9]+/).map(t=>t.replace(/^(ال|لل|بال|كال|فال|وال)/,'')).filter(t=>t.length>1 && !STOP.has(t)); }
function lev(a,b){ const m=a.length,n=b.length; if(!m)return n; if(!n)return m; const d=Array.from({length:m+1},(_,i)=>[i,...Array(n).fill(0)]); for(let j=1;j<=n;j++)d[0][j]=j; for(let i=1;i<=m;i++)for(let j=1;j<=n;j++)d[i][j]=Math.min(d[i-1][j]+1,d[i][j-1]+1,d[i-1][j-1]+(a[i-1]===b[j-1]?0:1)); return d[m][n]; }
function tokSim(a,b){ const L=Math.max(a.length,b.length); if(!L)return 0; return 1 - lev(a,b)/L; }
const qt = toks(req.title || req.new_title || '');
let best = null;
const allScored = [];
for (const c of cands) {
  const ct = toks(c.title);
  if (!qt.length || !ct.length) continue;
  let matched = 0;
  for (const q of qt) { if (ct.some(t => tokSim(q,t) >= 0.75)) matched++; }
  const coverage = matched / qt.length;          // كم من كلمات الطلب موجودة في العنوان
  const density  = matched / ct.length;          // وكم من كلمات العنوان مطابقة
  const score = Math.round(((coverage*0.65)+(density*0.35))*100)/100;
  const cand = {code: c.topic_code, title: c.title, score, coverage, density};
  allScored.push(cand);
  if (!best || score > best.score) best = cand;
}
const match = !!(best && best.score >= 0.6 && best.coverage >= 0.6);
const top3 = allScored.sort(function(a,b){return b.score-a.score;}).slice(0,3);
return [{json: Object.assign({}, req, {_dupCheck: {match, best, top: top3, checked: cands.length}})}];

let title=''; let best={}; let top=[];
try{ const j=$input.first().json; title=j.title||j.new_title||''; best=(j._dupCheck&&j._dupCheck.best)||{}; top=(j._dupCheck&&j._dupCheck.top)||[]; }catch(e){}
try{ const sd=$getWorkflowStaticData('global'); sd.dupFound=Array.isArray(sd.dupFound)?sd.dupFound:[];
sd.dupFound.unshift({requested:title, code:best.code||'', existing:best.title||'', score:best.score||0, at:new Date().toISOString().slice(0,10)});
if(sd.dupFound.length>30)sd.dupFound=sd.dupFound.slice(0,30); }catch(e){}
try{var sd2=$getWorkflowStaticData('global');sd2.pending=Array.isArray(sd2.pending)?sd2.pending:[];var pcode='DUP-'+(best.code||'?');sd2.pending=sd2.pending.filter(function(x){return x&&x['الرمز']!==pcode;});sd2.pending.unshift({'الرمز':pcode,'الباقة':'جديد','عنوان الموضوع':title,'الحالة المرجعية':'','حالة الإنتاج':'موجود مسبقًا','تاريخ الإنتاج':new Date().toISOString().slice(0,10),'رابط الملف (OneDrive)':'','الإصدار':'','ملاحظات':'✋ العرض موجود بالفعل. الأقرب: '+top.map(function(t){return t.code+' — '+t.title+' ('+Math.round((t.score||0)*100)+'٪)';}).join(' · ')+'. اطلب الأنسب منها كموضوع من الباقات الحالية.','النوع':'presentation'});if(sd2.pending.length>60)sd2.pending=sd2.pending.slice(0,60);}catch(e){}
return [{json:{'الرمز':best.code||'','العنوان':title,'حالة الإنتاج':'موجود مسبقًا','تاريخ الإنتاج':new Date().toISOString().slice(0,10),'ملاحظات':'✋ هذا العرض موجود بالفعل. الأقرب: '+top.map(function(t){return t.code+' — '+t.title+' ('+Math.round((t.score||0)*100)+'٪)';}).join(' · ')+'. لم يُنتَج محتوى مكرر.'}}];

// يسجل الفشل في البوابة ويقرر إعادة المحاولة
const b = ($input.first().json.body) || {};
const execId = String(b.executionId||'');
const sd = $getWorkflowStaticData('global');
const store = (sd.lastRequests && typeof sd.lastRequests==='object') ? sd.lastRequests : {};
const rec = store[execId];
const payload = rec && rec.payload ? rec.payload : null;
// حارس التكرار: بصمة الطلب
// الحارس محمول في الطلب نفسه (_retry) — محصن من سباق البيانات المشتركة
const prevRetries = payload ? Number(payload._retry || 0) : 99;
const canRetry = !!(payload && payload.task_type && prevRetries < 1);
const sig = payload ? [payload.task_type, payload.topic_code||'', payload.new_title||''].join('|') : '';
// سجل الحالة في البوابة
try {
  sd.pending = Array.isArray(sd.pending)?sd.pending:[];
  const title = payload ? (payload.new_title || payload.topic_code || '؟') : 'طلب غير معروف';
  const code = 'ERR-' + (execId ? execId.slice(-6) : 'x');
  sd.pending = sd.pending.filter(function(x){return x && x['الرمز']!==code;});
  sd.pending.unshift({'الرمز':code,'الباقة':payload?(payload.package||''):'','عنوان الموضوع':String(title),'الحالة المرجعية':'','حالة الإنتاج': canRetry ? 'إعادة محاولة تلقائية' : 'فشل تقني','تاريخ الإنتاج':new Date().toISOString().slice(0,10),'رابط الملف (OneDrive)':'','الإصدار':'','ملاحظات':'⚠️ عطل تقني في عقدة «'+String(b.errorNode||'؟')+'»: '+String(b.errorMessage||'').slice(0,160)+(canRetry?' — تُعاد المحاولة تلقائيًا الآن.':' — استُنفدت إعادة المحاولة؛ أعد الطلب يدويًا أو راجع n8n.'),'النوع': payload?(payload.output_type||''):''});
  if(sd.pending.length>60)sd.pending=sd.pending.slice(0,60);
} catch(e) {}
try{ if(!canRetry){ sd.analytics=Array.isArray(sd.analytics)?sd.analytics:[]; sd.analytics.push({at:new Date().toISOString(),topic:payload?String(payload.new_title||payload.topic_code||'؟'):'؟',hardFail:true,reason:(String(b.errorNode||'')+' — '+String(b.errorMessage||'')).slice(0,160)}); if(sd.analytics.length>200)sd.analytics=sd.analytics.slice(-200); } }catch(e){}
return [{json:{canRetry, retryPayload: canRetry ? Object.assign({}, payload, {_retry: prevRetries + 1, _fromQueue: 0}) : null, execId, sig}}];

const resp = $input.first().json || {};
let req = {}; try { req = $('تنظيم بيانات الطلب').first().json; } catch(e) {}
const title = req.new_title || req.topic_code || '؟';
const pos = resp.position != null ? resp.position : '؟';
try {
  const sd = $getWorkflowStaticData('global');
  sd.pending = Array.isArray(sd.pending)?sd.pending:[];
  const code = 'Q-' + String(title).slice(0,12) + '-' + String(pos);
  sd.pending = sd.pending.filter(function(x){return x && x['الرمز']!==code;});
  sd.pending.unshift({'الرمز':code,'الباقة':req.package||'','عنوان الموضوع':String(title),'الحالة المرجعية':'','حالة الإنتاج':'في الطابور','تاريخ الإنتاج':new Date().toISOString().slice(0,10),'رابط الملف (OneDrive)':'','الإصدار':'','ملاحظات':'📥 الطلب في طابور الإنتاج — المركز '+pos+(resp.duplicate?' (كان موجودًا في الطابور مسبقًا)':'')+'. سيُنتج تلقائيًا بالترتيب.','النوع':req.output_type||''});
  if(sd.pending.length>60)sd.pending=sd.pending.slice(0,60);
} catch(e) {}
return [{json:{queued:true, position: pos}}];

