أخرِج JSON صالحًا واحدًا فقط لكائن الشريحة، بلا أي نص آخر.
[للشرائح القانونية] لا تذكر غرامة أو رقم مادة نظامية أو عقوبة إلا إن وردت نصًّا في الموجز بمصدرها؛ وإلا اكتب توجيهًا عامًا بلا أرقام.

⚠️ حدود القالب الإلزامية (تفحصها لجنة التدقيق آليًا وأي تجاوز يعني الرفض وإعادة الدورة):
- العنوان ≤ 9 كلمات، وكل عنصر/نقطة/خطوة ≤ 14 كلمة
- عدد العناصر في الشريحة الواحدة: emergency ≤ 4 | cards وcardsDesc ≤ 6 | بقية الأنواع ≤ 8 (افعل ولا تفعل: كل عمود ≤ 7)
- العرض كاملًا 4–24 شريحة
- رقم الطوارئ الوحيد المسموح: 999 | يُمنع أي تاريخ مستقبلي | كل رقم أو إحصاء يجب أن يكون من الموجز المؤصّل حرفيًا

parameters.jsCode:
function pick(j){try{if(j.output&&j.output[0]&&j.output[0].content){for(const c of j.output[0].content){if(c&&c.text)return c.text;}}}catch(e){}if(typeof j.text==='string')return j.text;if(typeof j.content==='string')return j.content;return JSON.stringify(j);}
function ps(t){try{return JSON.parse(t);}catch(e){try{const m=String(t).match(/\{[\s\S]*\}/);return JSON.parse(m[0]);}catch(_){return null;}}}
const s=ps(pick($input.first().json));
return [{json:{slide:(s&&s.type)?s:null}}];

